query fetch_forecast_total_data($query: DAQueryInputMultiTable!) {
  daDataQueryMultiTable(queries: [$query]) {
    edges {
      node {
        dimensionMembers {
          uniqueID
          name
          dimensionLevelColumnName
          comments {
            measureName
            comment {
              isRecalculated
              isCommentAvailable
              value
              __typename
            }
            __typename
          }
          __typename
        }
        measureValues
        __typename
      }
      cursor
      __typename
    }
    pageInfo {
      totalRows
      hasNextPage
      __typename
    }
    __typename
  }
}
